-- E-Commerce Schema (Simplified) - 4 core tables for baseline testing
-- Used by: 01_basics_ecommerce dataset, unit tests, smoke tests

CREATE TABLE CUSTOMER_MASTER (
    CUST_ID     INT PRIMARY KEY,
    FULL_NAME   VARCHAR(200) NOT NULL,
    EMAIL       VARCHAR(150) UNIQUE NOT NULL,
    REGION_CODE VARCHAR(10),
    CREATED_AT  DATETIME DEFAULT CURRENT_TIMESTAMP,
    IS_ACTIVE   BOOLEAN DEFAULT TRUE
);

CREATE TABLE TB_PRODUCT (
    PRODUCT_ID   INT PRIMARY KEY,
    SKU          VARCHAR(50) UNIQUE NOT NULL,
    PRODUCT_NAME VARCHAR(300) NOT NULL,
    CATEGORY_ID  INT NOT NULL,
    UNIT_PRICE   DECIMAL(10,2) NOT NULL,
    IS_ACTIVE    BOOLEAN DEFAULT TRUE,
    CONSTRAINT fk_product_category FOREIGN KEY (CATEGORY_ID) REFERENCES TB_CATEGORY(CATEGORY_ID)
);

CREATE TABLE TB_CATEGORY (
    CATEGORY_ID        INT PRIMARY KEY,
    CATEGORY_NAME      VARCHAR(200) NOT NULL,
    PARENT_CATEGORY_ID INT,
    CONSTRAINT fk_cat_parent FOREIGN KEY (PARENT_CATEGORY_ID) REFERENCES TB_CATEGORY(CATEGORY_ID)
);

CREATE TABLE SALES_ORDER_HDR (
    ORDER_ID    BIGINT PRIMARY KEY,
    CUST_ID     INT NOT NULL,
    ORDER_DATE  DATE NOT NULL,
    TOTAL_AMT   DECIMAL(12,2) NOT NULL,
    STATUS_CODE VARCHAR(20) DEFAULT 'PENDING',
    PAYMENT_CONFIRMED_AT DATETIME,
    DELIVERED_AT DATETIME,
    CREATED_AT  DATETIME DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_order_customer FOREIGN KEY (CUST_ID) REFERENCES CUSTOMER_MASTER(CUST_ID),
    CONSTRAINT chk_status CHECK (STATUS_CODE IN ('PENDING','CONFIRMED','SHIPPED','DELIVERED','CANCELLED'))
);

CREATE TABLE ORDER_LINE_ITEM (
    LINE_ID    INT PRIMARY KEY,
    ORDER_ID   BIGINT NOT NULL,
    PRODUCT_ID INT NOT NULL,
    QUANTITY   INT NOT NULL CHECK (QUANTITY > 0),
    UNIT_PRICE DECIMAL(10,2) NOT NULL,
    LINE_AMT   DECIMAL(12,2) NOT NULL,
    CONSTRAINT fk_line_order   FOREIGN KEY (ORDER_ID)   REFERENCES SALES_ORDER_HDR(ORDER_ID),
    CONSTRAINT fk_line_product FOREIGN KEY (PRODUCT_ID) REFERENCES TB_PRODUCT(PRODUCT_ID)
);

CREATE TABLE PAYMENT (
    PAYMENT_ID     BIGINT PRIMARY KEY,
    ORDER_ID       BIGINT NOT NULL,
    PAYMENT_METHOD VARCHAR(50) NOT NULL,
    AMOUNT         DECIMAL(12,2) NOT NULL,
    STATUS_CODE    VARCHAR(20) DEFAULT 'PENDING',
    CONFIRMED_AT   DATETIME,
    CREATED_AT     DATETIME DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_payment_order FOREIGN KEY (ORDER_ID) REFERENCES SALES_ORDER_HDR(ORDER_ID),
    CONSTRAINT chk_payment_status CHECK (STATUS_CODE IN ('PENDING','CONFIRMED','FAILED','REFUNDED'))
);

CREATE TABLE SHIPMENT (
    SHIPMENT_ID    BIGINT PRIMARY KEY,
    ORDER_ID       BIGINT NOT NULL,
    WAREHOUSE_CODE VARCHAR(20),
    SHIPPED_AT     DATETIME,
    TRACKING_NUMBER VARCHAR(100),
    STATUS_CODE    VARCHAR(20) DEFAULT 'PREPARING',
    CONSTRAINT fk_shipment_order FOREIGN KEY (ORDER_ID) REFERENCES SALES_ORDER_HDR(ORDER_ID),
    CONSTRAINT chk_shipment_status CHECK (STATUS_CODE IN ('PREPARING','SHIPPED','IN_TRANSIT','DELIVERED'))
);
